        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), n1 = 0, n2 = 0, n3 = 0, n4 = 0, v = f._language == 'v', g = f.getItem('d68')._controlBehavior;
var l1 = g._getColumnOrder('stt_rec_pn'), l2 = g._getColumnOrder('stt_rec_kt'), l3 = g._getColumnOrder('stt_rec_hd'), l4 = g._getColumnOrder('stt_rec_tl');
var e1 = (v ? 'Thông tin nhà cung cấp của phiếu xuất trả lại nhà cung cấp thực tế phải giống với phiếu nhập, phiếu kiểm định hoặc hóa đơn.' : 'Return Goods to Supplier should have same supplier information as Purchase Receipt, QA Transaction, Purchase Invoice.');
var e2 = (v ? 'Không được chuyển vào sổ cái khi xuất trả lại từ phiếu kiểm định.' : 'Items returned from QA Transaction should not be posted to General Ledger.');
var e3 = (v ? 'Dữ liệu trong chi tiết chỉ được lấy số liệu từ phiếu nhập, phiếu kiểm định hóa đơn hoặc hóa đơn trả lại.' : 'Data in grid form must be extracted from Purchase Receipt, QA Transaction, Purchase Invoice, Return Invoice.');
var t = f.getItemValue('ma_kh'), q = (f.getItemValue('status') == 3);
for (var i = 1; i <= g._rowCount; i++) {
  var v1 = (g._getItemValue(i, l1) != ''), v2 = (g._getItemValue(i, l2) != ''), v3 = (g._getItemValue(i, l3) != ''), v4 = (g._getItemValue(i, l4) != '');
  if (v1 || v2 || v3 || v4) {
    var u = g._getItem(i, 1)._customerIdentity;
    if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
    if (t != u) {
      $func.hideWait(id);
      $message.show(e1, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
      f._checked = false;
      break;
    }
    if (f._checked) {
      if (v3) {if (n3 == 0) n3 = 1;}
      else {
        if (v2) {if (n2 == 0) n2 = 1;}
        else {
          if (v1) {if (n1 == 0) n1 = 1;}
          else {
            if (v4) {if (n4 == 0) n4 = 1;}
          }
        }
      }
    }
  }
  if (q && v2) {
    $func.hideWait(id);
    $message.show(e2, String.format('$find(\'{0}\').getItem(\'status\').focus()', id));
    f._checked = false;
    break;
  }
}

if (f._checked) {
  if (n1 + n2 + n3 + n4 > 1) {
    f._errorWarningObject = g._getItem(1, g._getColumnOrder('ma_vt'));
    $func.hideWait(id);
    $message.show(e3, String.format('var f = $find(\'{0}\');f.focus(\'d68\');f._errorWarningObject.focus()', id));
    f._checked = false;
  }
}
/* </flatten> */
